import os  # For operating system commands.
import subprocess  # For running OS commands in a shell.

def main():
    """Main function for package deployer."""

    # Get current working directory from os, set it as cwd.
    cwd = os.getcwd()
    
    # Run pip install command, pass the path to requirements file as argument.
    subprocess.check_output(f"pip install -r {cwd}/requirements.txt", shell=True)

    # Start app test using pytest and return the exit code for status checking.
    exitcode = os.system("pytest") 

    # If exit code is 0 then print "All tests passed". Else print error message. 
    if(exitcode == 0):
        print('All tests passed')
    else: 
        raise Exception('Some test cases failed!!')

    # Move to app directory and copy the generated python scripts into deploy_package folder.
    os.chdir("./app")
    subprocess.check_output(f"cp *.py ../../deploy_package", shell=True)

# Calling main function to run the entire program.  
if __name__ == '__main__': 
    main()